import React from 'react';
import InAppPurchase from '@react-native-iap/in-app-purchase';
import ApplePay from '@react-native-applepay/applepay';
import GooglePay from '@google-pay/react-native';

class PaymentModule extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      purchase: null,
      paymentMethods: [],
    };
  }

  componentDidMount() {
    InAppPurchase.getProducts(['product_id_1', 'product_id_2']).then(products => {
      this.setState({ products });
    });

    ApplePay.configure({
      merchantId: 'merchant_id',
    });

    GooglePay.initialize({
      paymentRequest: {
        apiVersion: 2,
        apiVersionMinor: 0,
        allowedPaymentMethods: ['credit_card', 'debit_card'],
      },
    });
  }

  handlePurchase(productId) {
    InAppPurchase.purchase(productId).then(purchase => {
      this.setState({ purchase });
    });
  }

  handleApplePay() {
    ApplePay.presentApplePay({
      total: {
        label: 'Total',
        amount: 10.0,
      },
    }).then(result => {
      console.log(result);
    });
  }

  handleGooglePay() {
    GooglePay.presentGooglePay({
      paymentRequest: {
        apiVersion: 2,
        apiVersionMinor: 0,
        allowedPaymentMethods: ['credit_card', 'debit_card'],
        total: {
          label: 'Total',
          amount: 10.0,
        },
      },
    }).then(result => {
      console.log(result);
    });
  }

  render() {
    return (
      <View>
        {this.state.products.map(product => (
          <Button title={product.title} onPress={() => this.handlePurchase(product.productId)} />
        ))}
        <Button title="Apple Pay" onPress={this.handleApplePay} />
        <Button title="Google Pay" onPress={this.handleGooglePay} />
      </View>
    );
  }
}

export default PaymentModule;